import pytest

# Assuming the function is in a module named 'your_module'
from your_module import deep_get

class TestDeepGet:
    def test_happy_path_single_level(self):
        d = {'a': 1}
        assert deep_get(d, 'a') == 1

    def test_happy_path_nested(self):
        d = {'a': {'b': {'c': 42}}}
        assert deep_get(d, 'a.b.c') == 42

    def test_happy_path_with_default_ignored(self):
        d = {'a': {'b': 2}}
        assert deep_get(d, 'a.b', 'default') == 2

    def test_key_not_found_single_level(self):
        d = {'a': 1}
        assert deep_get(d, 'b') is None
        assert deep_get(d, 'b', 'default') == 'default'

    def test_key_not_found_nested(self):
        d = {'a': {'b': 1}}
        assert deep_get(d, 'a.c') is None
        assert deep_get(d, 'a.c.d', 'default') == 'default'

    def test_empty_keys(self):
        d = {'a': 1}
        # Empty keys should return the dict itself, but since it's not a key, maybe default?
        # Wait, split('.') on '' gives [''], so d.get('', default), which for dict is default.
        assert deep_get(d, '') is None
        assert deep_get(d, '', 'default') == 'default'

    def test_keys_with_empty_parts(self):
        d = {'a': {'': {'b': 3}}}
        assert deep_get(d, 'a..b') == 3
        # But if empty key not present, it should fail at that point.
        d2 = {'a': {'b': 2}}
        assert deep_get(d2, 'a..b') is None  # Because d2['a'] is dict, but get('', default) fails.

    def test_non_dict_initial(self):
        # If d is not a dict, should return default immediately.
        assert deep_get('not a dict', 'a.b') is None
        assert deep_get(42, 'a', 'default') == 'default'

    def test_non_dict_intermediate(self):
        d = {'a': {'b': 'not a dict'}}
        assert deep_get(d, 'a.b.c') is None  # Because 'not a dict' is not a dict, so return default.

    def test_deep_nesting(self):
        d = {'a': {'b': {'c': {'d': {'e': 100}}}}}
        assert deep_get(d, 'a.b.c.d.e') == 100

    def test_default_none_explicit(self):
        d = {}
        assert deep_get(d, 'missing', None) is None

    def test_keys_with_multiple_dots(self):
        d = {'a.b': {'c': 5}}  # Key contains dot
        assert deep_get(d, 'a.b.c') == 5  # This should work since 'a.b' is a key.
